// Revisión técnica solar con cascada de proveedores: Groq (gratis) → Gemini (gratis) → Claude Haiku (paga).
// Env vars opcionales (usar la primera disponible):
//   GROQ_API_KEY                       → Groq llama-3.3-70b-versatile (gratis, alto rate limit)
//   GEMINI_API_KEY | GOOGLE_AI_KEY     → Google Gemini 2.0 Flash (gratis hasta cuota)
//   ANTHROPIC_API_KEY                  → Claude Haiku 4.5 (paga, fallback de calidad)
// Input body: { context: 'review'|'sizing'|'explain', payload: {...} }

const src = $input.first().json;
const body = src.body || src;
const context = (body.context || 'review').toString();
const payload = body.payload || {};

// Acceso tolerante a $env: el task runner puede denegarlo (TypeError en getter).
const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const GROQ = safeEnv('GROQ_API_KEY');
// Acepta el alias GOOGLE_AI_KEY (nombre histórico en Railway de SolarHub) además del estándar GEMINI_API_KEY.
const GEMINI = safeEnv('GEMINI_API_KEY') || safeEnv('GOOGLE_AI_KEY');
const CLAUDE = safeEnv('ANTHROPIC_API_KEY');

if (!GROQ && !GEMINI && !CLAUDE) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'Ninguna API key configurada. Define al menos una de: GROQ_API_KEY, GEMINI_API_KEY (o GOOGLE_AI_KEY), ANTHROPIC_API_KEY.' } }];
}

const system = 'Eres un ingeniero eléctrico especializado en sistemas solares fotovoltaicos en Colombia. Conoces RETIE, CREG 038/2014, CREG 174/2021 (AGPE), Ley 1715, estándares NEC/IEC. Analiza el dimensionamiento que te envía el cotizador y devuelve observaciones concretas, accionables y técnicas. Usa español neutro.';

// Esquema de campos que el frontend puede aplicar automáticamente.
// El modelo debe proponer 'actions' SOLO con field/value de este listado.
const applyableSchema = `Campos aplicables y valores válidos:\n\n- systemType: 'on-grid' | 'hybrid' | 'off-grid'\n- monthlyKwh: number > 0\n- battQty: integer 1..12 (solo si systemType != 'on-grid')\n- busVoltage: 12 | 24 | 48 (solo si systemType != 'on-grid')\n- backupHours: 2 | 4 | 6 | 8 | 12 | 24 (solo si systemType == 'hybrid')\n- autonomyDays: 1 | 2 | 3 (solo si systemType == 'off-grid')\n- criticalPct: 25 | 50 | 75 | 100 (solo si systemType == 'hybrid')\n- acometida: 'monofasico' | 'bifasico' | 'trifasico'\n- availableArea: number en m² > 0\n- wantsExcedentes: boolean (true = inscribir AGPE para vender excedentes)\n\nNO inventes IDs de panel/inversor/batería: el catálogo no se aplica programáticamente.`;

const userPrompt = `Contexto: ${context}\n\nSistema a revisar (JSON):\n${JSON.stringify(payload, null, 2)}\n\n${applyableSchema}\n\nDevuelve SOLO JSON válido con esta forma exacta (sin markdown, sin texto adicional):\n{\n  \"summary\": string,\n  \"findings\": string[],\n  \"warnings\": string[],\n  \"suggestions\": string[],\n  \"actions\": [{ \"field\": string, \"value\": any, \"label\": string, \"reason\": string }]\n}\n\n═══ REGLAS DURAS DE COHERENCIA (no negociables) ═══\n\n[RD-1] systemType es DECISIÓN ARQUITECTÓNICA del usuario. Refleja si tiene red eléctrica disponible o no:\n  • off-grid = el predio NO tiene acometida ni red disponible (zona rural aislada, finca, etc.). NUNCA propongas cambiar systemType desde off-grid hacia 'hybrid' u 'on-grid'. Sería físicamente imposible.\n  • on-grid = tiene red, sin baterías. Solo propón cambio a 'hybrid' si hay evidencia EXPLÍCITA en el payload de necesidad de respaldo (ej: cargas críticas, cortes frecuentes mencionados, backupHours>0). NO basta con 'sería bueno tener baterías'.\n  • hybrid = tiene red + baterías. No propongas regresar a 'on-grid' ni a 'off-grid'.\n\n[RD-2] wantsExcedentes (AGPE) requiere red. NUNCA propongas wantsExcedentes:true si systemType=='off-grid'. AGPE/CREG 174-2021 implica inyección a red, imposible sin acometida.\n\n[RD-3] availableArea: solo propón cambio si el valor actual es 0/null o claramente irreal (ej: 5 m² para 20 paneles). NO propongas REDUCIR el área disponible — el área es declaración del usuario sobre su techo, no se 'optimiza' a la baja.\n\n[RD-4] battQty / busVoltage / backupHours / autonomyDays / criticalPct: solo aplican si systemType ya es 'hybrid' u 'off-grid'. Si systemType=='on-grid' NO propongas estos campos (no aplican).\n\n[RD-5] acometida: solo propón cambio si la potencia del sistema lo exige (ej: kWp>10 ⇒ trifasico). NO cambies de bifasico a trifasico solo 'por seguridad'.\n\n═══ ESTRUCTURA DE LA RESPUESTA ═══\n\n- summary: 1-2 frases ejecutivas.\n- findings: 2-5 observaciones técnicas clave del payload.\n- warnings: alertas críticas (voltaje, normativa). Vacío si no hay.\n- suggestions: 2-4 recomendaciones en lenguaje natural. Aquí SÍ puedes mencionar mejoras que NO sean acciones programáticas (ej: 'considerar cambiar marca de panel'). Para off-grid, las suggestions deben enfocarse en autonomía, banco de baterías y gestión de cargas — NUNCA en red eléctrica ni AGPE.\n- actions (CRÍTICO): por cada suggestion que SÍ pueda traducirse a un campo aplicable Y que respete las RD-1 a RD-5, agrega un objeto. Vacío si la config ya está bien o si las suggestions caen fuera del esquema/violan reglas duras.\n\nEjemplos de mapeo válido suggestion → action:\n  • on-grid con cobertura >150% sin AGPE: action = { field: \"wantsExcedentes\", value: true, label: \"Inscribir AGPE\", reason: <breve> }\n  • on-grid con backupHours>0 declarado por usuario: action = { field: \"systemType\", value: \"hybrid\", label: \"Cambiar a híbrido\", reason: <breve> }\n  • hybrid u off-grid con banco subdimensionado: action = { field: \"battQty\", value: N, label: \"Banco de N baterías\", reason: <breve> }\n  • hybrid u off-grid con bus 24V y kWp>5: action = { field: \"busVoltage\", value: 48, label: \"Bus 48 V DC\", reason: <breve> }\n  • availableArea==null o irreal y techo Google insuficiente: action = { field: \"availableArea\", value: <m²-real>, label: \"Área techo\", reason: <breve> }\n  • kWp>10 con acometida bifasico: action = { field: \"acometida\", value: \"trifasico\", label: \"Acometida trifásica\", reason: <breve> }\n  • off-grid con autonomía 1 día: action = { field: \"autonomyDays\", value: 2 o 3, label: \"Autonomía N días\", reason: <breve> }\n\nEjemplos PROHIBIDOS (no los devuelvas):\n  ✗ off-grid → hybrid (viola RD-1)\n  ✗ off-grid → wantsExcedentes:true (viola RD-2)\n  ✗ availableArea: 60 → 50 (viola RD-3)\n  ✗ on-grid → battQty:N (viola RD-4)\n\n- 'label' ≤60 chars, 'reason' ≤140 chars y debe citar el dato del payload que justifica el cambio.\n- NO inventes IDs de catálogo (panel/inversor/batería); el frontend NO los aplica.\n- Trabaja solo con los datos del payload.`;

function extractJson(text) {
  if (!text) return null;
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) return null;
  try { return JSON.parse(m[0]); } catch (_) { return null; }
}

async function callGroq() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'authorization': `Bearer ${GROQ}`,
      'content-type': 'application/json',
    },
    body: {
      model: 'llama-3.3-70b-versatile',
      max_tokens: 1500,
      temperature: 0.2,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userPrompt },
      ],
    },
    json: true,
  });
  const text = r?.choices?.[0]?.message?.content || '';
  const usage = r?.usage || {};
  return { parsed: extractJson(text), provider: 'groq-llama-3.3-70b', tokens: { in: usage.prompt_tokens || 0, out: usage.completion_tokens || 0 }, raw: text };
}

async function callGemini() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${encodeURIComponent(GEMINI)}`,
    headers: { 'content-type': 'application/json' },
    body: {
      systemInstruction: { parts: [{ text: system }] },
      contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
      generationConfig: { temperature: 0.2, maxOutputTokens: 1500, responseMimeType: 'application/json' },
    },
    json: true,
  });
  const text = (r?.candidates?.[0]?.content?.parts || []).map(p => p.text || '').join('\n').trim();
  const usage = r?.usageMetadata || {};
  return { parsed: extractJson(text), provider: 'gemini-2.0-flash', tokens: { in: usage.promptTokenCount || 0, out: usage.candidatesTokenCount || 0 }, raw: text };
}

async function callClaude() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': CLAUDE,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
    },
    body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1500,
      system,
      messages: [{ role: 'user', content: userPrompt }],
    },
    json: true,
  });
  const text = (r.content || []).map(c => c.text || '').join('\n').trim();
  const usage = r.usage || {};
  return { parsed: extractJson(text), provider: 'claude-haiku-4-5', tokens: { in: usage.input_tokens || 0, out: usage.output_tokens || 0 }, raw: text };
}

const ladder = [];
if (GROQ)   ladder.push({ name: 'groq',   fn: callGroq.bind(this) });
if (GEMINI) ladder.push({ name: 'gemini', fn: callGemini.bind(this) });
if (CLAUDE) ladder.push({ name: 'claude', fn: callClaude.bind(this) });

const attempts = [];
let result = null;
for (const step of ladder) {
  try {
    const out = await step.fn();
    if (out && out.parsed) { result = out; break; }
    attempts.push({ provider: step.name, error: 'invalid_json', raw: (out?.raw || '').slice(0, 200) });
  } catch (e) {
    attempts.push({ provider: step.name, error: (e && e.message) ? e.message.slice(0, 200) : 'unknown' });
  }
}

if (!result) {
  return [{ json: { ok: false, reason: 'all_providers_failed', attempts } }];
}

const parsed = result.parsed;
const rawActions = Array.isArray(parsed.actions) ? parsed.actions : [];
const allowedFields = new Set(['systemType','monthlyKwh','battQty','busVoltage','backupHours','autonomyDays','criticalPct','acometida','availableArea','wantsExcedentes']);

// Reglas duras de coherencia (servidor) — descartan actions inválidas aunque el modelo las devuelva.
const currentSysType = payload?.systemType;
const currentArea = Number(payload?.roof?.availableM2 || payload?.availableArea || 0) || null;
const sanitizeAction = (a) => {
  if (!a || typeof a !== 'object' || !allowedFields.has(a.field)) return null;
  // RD-1: nunca cambiar systemType desde off-grid
  if (a.field === 'systemType' && currentSysType === 'off-grid') return null;
  // RD-2: AGPE imposible en off-grid
  if (a.field === 'wantsExcedentes' && currentSysType === 'off-grid' && a.value === true) return null;
  // RD-3: no reducir área disponible
  if (a.field === 'availableArea' && currentArea && Number(a.value) < currentArea) return null;
  // RD-4: campos de batería/bus solo si NO es on-grid
  if (['battQty','busVoltage','backupHours','autonomyDays','criticalPct'].includes(a.field) && currentSysType === 'on-grid') return null;
  return { field: String(a.field), value: a.value, label: String(a.label || '').slice(0, 80), reason: String(a.reason || '').slice(0, 200) };
};
const actions = rawActions.map(sanitizeAction).filter(Boolean);

return [{ json: {
  summary: parsed.summary || '',
  findings: Array.isArray(parsed.findings) ? parsed.findings : [],
  warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
  suggestions: Array.isArray(parsed.suggestions) ? parsed.suggestions : [],
  actions,
  provider: result.provider,
  tokens: result.tokens,
  attempts,
} }];
